   .making-offer-box {
  background: #e9e1ea; /* light purple */
  border-radius: 14px;
  padding: 16px 18px;
  margin: 20px 0;
  max-width:340px;
}

.making-offer-inner {
  display: flex;
  align-items: center;
  gap: 12px;
}

.making-offer-icon {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: linear-gradient(180deg, #FBE284 0%, #C19750 52.4%, #955D27 75%, #DBA926 100%);
  display: flex;
  align-items: center;
  justify-content: center;
}

.making-offer-icon svg {
  background: #e9e1ea; /* same as parent bg */
  border-radius: 50%;
  padding: 6px;
  width:28px;
  height:28px

}

.making-offer-divider {
  width: 1px;
  height: 40px;
  background: #bfaec2;
}

.making-offer-content {
  display: flex;
  flex-direction: column;
}

.making-offer-title {
 background: linear-gradient(180deg, #4D2753 0%, #1C0E2B 142.55%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  margin: 0;

  font-family: Helvetica;
  font-weight: 400;
  font-size: 14.49px;
  line-height: 100%;
  letter-spacing: 0%;

}

.making-offer-save {
  background: linear-gradient(180deg, #4D2753 0%, #1C0E2B 142.55%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  margin: 8px 0 0;

  font-family: Helvetica;
  font-weight: 800;
  font-size: 14.49px;
  line-height: 100%;
  letter-spacing: 0%;
}






